// Normaliser les métadonnées du document
const items = $input.all();

const normalized = items.map(item => {
  const data = item.json;

  return {
    json: {
      key: data.key || data.doc_key || 'unknown',
      title: data.title || 'Documentation sans titre',
      urlMatch: Array.isArray(data.urlMatch) 
        ? data.urlMatch 
        : (data.urlMatch ? [data.urlMatch] : []),
      docUrlOrPath: data.docUrlOrPath || data.path || data.url || '',
      tags: data.tags || [],
      timestamp: new Date().toISOString(),
      source: 'n8n-upload'
    },
    binary: item.binary
  };
});

return normalized;

// Préparer les données pour auto-summarize
const items = $input.all();

const prepared = items.map(item => {
  const data = item.json;

  return {
    json: {
      url: data.url || 'https://example.com',
      text: data.text || data.content || '',
      html: data.html || '',
      timestamp: new Date().toISOString(),
      source: 'n8n-auto-summarize'
    }
  };
});

return prepared;

// Préparer les données pour SmartTicket analysis
const items = $input.all();

const prepared = items.map(item => {
  const data = item.json;

  return {
    json: {
      url: data.url || '',
      ticketId: data.ticketId || data.id || '',
      source: data.source || 'mantis',
      timestamp: new Date().toISOString(),
      workflow_source: 'n8n-smartticket'
    }
  };
});

return prepared;

// Construire la réponse finale pour upload workflow
const items = $input.all();

const ingestResult = items[0]?.json || {};
const summaryResult = items[1]?.json || {};

return [{
  json: {
    status: 'success',
    workflow: 'upload',
    key: ingestResult.key,
    title: ingestResult.title,
    mapping_updated: !!ingestResult.status,
    summary_generated: !!summaryResult.status,
    summary_excerpt: summaryResult.summary 
      ? summaryResult.summary.substring(0, 150) + '...'
      : 'Non disponible',
    endpoints_called: ['/ingest', '/summarize'],
    timestamp: new Date().toISOString()
  }
}];

// Construire la réponse finale pour auto-summarize (V3.0 - sans common_errors/faqs)
const items = $input.all();

const result = items[0]?.json || {};

return [{
  json: {
    status: 'success',
    workflow: 'auto-summarize',
    url: result.url,
    summary_generated: !!result.summary,
    summary: result.summary || '',
    checklist: result.checklist || [],
    generated_at: result.generated_at || new Date().toISOString(),
    source: result.source || 'auto-summary',
    is_temporary: result.is_temporary !== undefined ? result.is_temporary : true,
    endpoint_called: '/auto-summarize',
    timestamp: new Date().toISOString(),
    note: 'V3.0: common_errors et faqs supprimés'
  }
}];

// Construire la réponse finale pour SmartTicket analysis (Pipeline V3.0)
const items = $input.all();

const result = items[0]?.json || {};

return [{
  json: {
    status: result.status || 'unknown',
    workflow: 'smartticket-analysis',
    pipeline_version: '3.0',

    // Étape 1: Complétude (barrière)
    completeness: result.completeness || null,
    completeness_score: result.completeness?.score || 0,
    completeness_status: result.completeness?.status || 'unknown',
    ticket_rejected: result.status === 'rejected',

    // Étape 2: Résumé (si accepté)
    summary: result.summary || null,
    checklist: result.checklist || [],

    // Étape 3: Difficulté (si accepté)
    difficulty: result.difficulty || null,
    difficulty_level: result.difficulty?.level || 'unknown',
    difficulty_score: result.difficulty?.score || 0,

    // Étape 4: Tickets similaires (si accepté)
    similar_tickets: result.similar_tickets || [],
    similar_count: result.similar_tickets?.length || 0,

    // Métadonnées
    ticket_id: result.ticket_id || result.ticketId || '',
    ticket_title: result.ticket_title || result.title || '',
    endpoint_called: '/smartticket/full-analysis',
    timestamp: new Date().toISOString(),
    note: 'Pipeline V3.0 avec 4 étapes séquentielles'
  }
}];
